<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Lab Technician — Professional Services</title>
  <link rel="stylesheet" href="styles.css" />
</head>
<body>
  <header class="hero" role="banner">
    <div class="container">
      <h1 id="hero-title">Professional Lab Technician</h1>
      <p class="subtitle">Reliable, accurate, and efficient laboratory support</p>
      <a class="cta" href="#contact">Contact Me</a>
    </div>
  </header>

  <main>
    <section class="services" aria-labelledby="services-title">
      <div class="container">
        <h2 id="services-title">Services</h2>
        <ul class="service-list">
          <li>
            <h3>Sample Processing</h3>
            <p>Specimen handling, preparation, and documentation with strict chain-of-custody.</p>
          </li>
          <li>
            <h3>Quality Control</h3>
            <p>Calibration, validation, and routine QC checks to maintain compliance.</p>
          </li>
          <li>
            <h3>Equipment Maintenance</h3>
            <p>Routine upkeep and troubleshooting for key laboratory instruments.</p>
          </li>
        </ul>
      </div>
    </section>

    <section id="contact" class="contact" aria-labelledby="contact-title">
      <div class="container">
        <h2 id="contact-title">Get in touch</h2>
        <form id="contact-form" novalidate>
          <div class="field">
            <label for="name">Name</label>
            <input type="text" id="name" name="name" required />
          </div>
          <div class="field">
            <label for="email">Email</label>
            <input type="email" id="email" name="email" required />
          </div>
          <div class="field">
            <label for="message">Message</label>
            <textarea id="message" name="message" rows="5" required></textarea>
          </div>
          <button type="submit" class="cta">Send Message</button>
        </form>
      </div>
    </section>
  </main>

  <footer class="footer">
    <div class="container">
      <small>&copy; <span id="year"></span> Lab Technician</small>
    </div>
  </footer>

  <script src="script.js"></script>
</body>
</html>
"},{"path":"styles.css","content":"/* Color palette: red/black/white only */
:root {
  --red: #e10600;
  --black: #111111;
  --white: #ffffff;
}

* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji";
  line-height: 1.5;
  color: var(--black);
  background: var(--white);
}

.container {
  width: 100%;
  max-width: 960px;
  margin: 0 auto;
  padding: 0 1rem;
}

.hero {
  background: var(--black);
  color: var(--white);
  padding: 4rem 0 3rem;
  text-align: center;
}
.hero #hero-title {
  margin: 0 0 0.5rem;
  font-size: clamp(2rem, 4vw + 1rem, 3rem);
  letter-spacing: 0.5px;
}
.hero .subtitle {
  margin: 0 0 1.5rem;
  color: var(--white);
  opacity: 0.85;
}
.cta {
  display: inline-block;
  background: var(--red);
  color: var(--white);
  text-decoration: none;
  padding: 0.75rem 1.25rem;
  border-radius: 4px;
  font-weight: 600;
  border: 2px solid var(--red);
}
.cta:hover,
.cta:focus { filter: brightness(0.95); }

.services { padding: 2.5rem 0; }
.services h2 { margin-top: 0; }
.service-list {
  list-style: none;
  margin: 1rem 0 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}
.service-list li {
  border: 1px solid #e6e6e6;
  padding: 1rem;
  border-left: 4px solid var(--red);
  background: var(--white);
}
.service-list h3 { margin: 0 0 0.5rem; }

.contact { padding: 2.5rem 0; background: #fafafa; }
.field { margin-bottom: 1rem; }
label { display: block; font-weight: 600; margin-bottom: 0.25rem; }
input, textarea {
  width: 100%;
  padding: 0.6rem 0.7rem;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  font: inherit;
}

.footer { padding: 1rem 0 2rem; text-align: center; color: #666; }

@media (prefers-color-scheme: dark) {
  body { background: #0b0b0b; color: var(--white); }
  .services .service-list li { background: #111; border-color: #222; }
  .contact { background: #0f0f0f; }
  input, textarea { background: #0c0c0c; color: var(--white); border-color: #222; }
  .footer { color: #aaa; }
}
"},{"path":"script.js","content":"(function () {
  // Year in footer
  try {
    var y = document.getElementById('year');
    if (y) y.textContent = String(new Date().getFullYear());
  } catch (_) {}

  // Contact form alert (no backend)
  try {
    var form = document.getElementById('contact-form');
    if (form) {
      form.addEventListener('submit', function (e) {
        e.preventDefault();
        alert('Thank you! Your message has been noted.');
        form.reset();
      });
    }
  } catch (_) {}
})();
